{"path":"components/controller/controller.c","content":"#include "controller.h"

#include <stddef.h>

static void controller_reset(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

static controller_output_t controller_make_output(const controller_t *controller, bool changed, bool timed_out)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = CONTROLLER_STATE_SAFE_VENT_NAME,
        .changed = changed,
        .timed_out = timed_out,
    };

    if (controller != NULL) {
        output.compressor_on = controller->compressor_on;
        output.vent_open = controller->vent_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
    }

    return output;
}

static bool controller_sensor_timed_out(uint32_t now_ms, uint32_t last_ms)
{
    return (uint32_t) (now_ms - last_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static bool controller_has_fresh_sensors(const controller_t *controller, uint32_t now_ms)
{
    if ((controller == NULL) || !controller->has_valid_pressure || !controller->has_valid_door) {
        return false;
    }

    return !controller_sensor_timed_out(now_ms, controller->last_pressure_ms) &&
           !controller_sensor_timed_out(now_ms, controller->last_door_ms);
}

static void controller_set_safe_vent(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

static void controller_set_pressurizing(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = true;
    controller->vent_open = false;
    controller->state = CONTROLLER_STATE_PRESSURIZING;
}

static void controller_set_relieving(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_RELIEVING;
}

static void controller_set_holding(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->state = CONTROLLER_STATE_HOLDING;
}

void controller_init(controller_t *controller)
{
    controller_reset(controller);
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    const bool controller_was_null = (controller == NULL);
    controller_t snapshot;
    bool changed = false;
    bool timed_out = false;
    bool use_snapshot = false;

    if (controller_was_null) {
        controller_reset(&snapshot);
        controller = &snapshot;
    }

    const bool previous_compressor_on = controller->compressor_on;
    const bool previous_vent_open = controller->vent_open;
    const controller_state_t previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        if (!controller->has_valid_door || controller_sensor_timed_out(input.now_ms, controller->last_door_ms)) {
            controller_set_safe_vent(controller);
            break;
        }

        if (controller->door_closed) {
            if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                controller_set_pressurizing(controller);
            } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                controller_set_relieving(controller);
            } else {
                controller_set_holding(controller);
            }
        } else {
            controller_set_safe_vent(controller);
        }
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        controller_set_safe_vent(controller);
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        if (!controller->has_valid_pressure || controller_sensor_timed_out(input.now_ms, controller->last_pressure_ms)) {
            controller_set_safe_vent(controller);
            break;
        }

        if (controller->last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            controller_set_pressurizing(controller);
        } else if (controller->last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            controller_set_relieving(controller);
        } else {
            controller_set_holding(controller);
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        controller_set_safe_vent(controller);
        timed_out = (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT);
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        if (!controller_has_fresh_sensors(controller, input.now_ms)) {
            controller_set_safe_vent(controller);
            if (controller->has_valid_pressure && controller->has_valid_door) {
                timed_out = true;
            }
        } else {
            controller->compressor_on = previous_compressor_on;
            controller->vent_open = previous_vent_open;
            controller->state = previous_state;
        }
        break;
    }

    changed = (controller->compressor_on != previous_compressor_on) || (controller->vent_open != previous_vent_open);

    if (input.kind == CONTROLLER_INPUT_NONE && !changed && !timed_out) {
        use_snapshot = controller_was_null;
    }

    if (controller_was_null) {
        (void) use_snapshot;
        return controller_make_output(&snapshot, changed, timed_out);
    }

    return controller_make_output(controller, changed, timed_out);
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_VENT:
        return CONTROLLER_STATE_SAFE_VENT_NAME;
    case CONTROLLER_STATE_PRESSURIZING:
        return CONTROLLER_STATE_PRESSURIZING_NAME;
    case CONTROLLER_STATE_HOLDING:
        return CONTROLLER_STATE_HOLDING_NAME;
    case CONTROLLER_STATE_RELIEVING:
        return CONTROLLER_STATE_RELIEVING_NAME;
    default:
        return CONTROLLER_STATE_SAFE_VENT_NAME;
    }
}
